import{_ as e,o as r,c as a,ao as l}from"./chunks/framework.BOTctrRk.js";const i="/PureFFT.jl/dev/assets/comparison.BB4405Ib.png",y=JSON.parse('{"title":"Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"benchmarks.md","filePath":"benchmarks.md","lastUpdated":null}'),s={name:"benchmarks.md"};function d(g,t,n,o,h,x){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="Benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#Benchmarks" aria-label="Permalink to &quot;Benchmarks {#Benchmarks}&quot;">​</a></h1><p>All benchmarks: AMD Zen 5 (znver5, AVX-512), single-thread, in-place, planning excluded. Input: <code>Vector{ComplexF64}</code>, power-of-two sizes. FFTW at <code>MEASURE</code> flag. RustFFT with <code>IgnoreArrayChecks</code>. PureFFT <code>:fast</code> (autotuned).</p><h2 id="GFLOP/s-comparison" tabindex="-1">GFLOP/s comparison <a class="header-anchor" href="#GFLOP/s-comparison" aria-label="Permalink to &quot;GFLOP/s comparison {#GFLOP/s-comparison}&quot;">​</a></h2><p><img src="'+i+'" alt=""></p><p>Flop model: <code>5 · N · log2(N)</code> (standard radix-2 count).</p><h2 id="PureFFT-:fast-vs-rustfft-GFLOP/s" tabindex="-1">PureFFT <code>:fast</code> vs rustfft (GFLOP/s) <a class="header-anchor" href="#PureFFT-:fast-vs-rustfft-GFLOP/s" aria-label="Permalink to &quot;PureFFT `:fast` vs rustfft (GFLOP/s) {#PureFFT-:fast-vs-rustfft-GFLOP/s}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">n</th><th style="text-align:right;">PureFFT <code>:fast</code></th><th style="text-align:right;">rustfft-scalar</th><th style="text-align:right;">rustfft-AVX</th><th style="text-align:right;">vs scalar</th><th style="text-align:right;">vs AVX</th></tr></thead><tbody><tr><td style="text-align:right;">1024</td><td style="text-align:right;">38</td><td style="text-align:right;">21</td><td style="text-align:right;">44</td><td style="text-align:right;"><strong>1.8×</strong></td><td style="text-align:right;">0.86×</td></tr><tr><td style="text-align:right;">4096</td><td style="text-align:right;">40</td><td style="text-align:right;">19</td><td style="text-align:right;">48</td><td style="text-align:right;"><strong>2.1×</strong></td><td style="text-align:right;">0.83×</td></tr><tr><td style="text-align:right;">16384</td><td style="text-align:right;">37</td><td style="text-align:right;">20</td><td style="text-align:right;">44</td><td style="text-align:right;"><strong>1.9×</strong></td><td style="text-align:right;">0.83×</td></tr><tr><td style="text-align:right;">65536</td><td style="text-align:right;">37</td><td style="text-align:right;">19</td><td style="text-align:right;">35</td><td style="text-align:right;"><strong>1.9×</strong></td><td style="text-align:right;"><strong>1.04×</strong></td></tr><tr><td style="text-align:right;">262144</td><td style="text-align:right;">28</td><td style="text-align:right;">17</td><td style="text-align:right;">30</td><td style="text-align:right;"><strong>1.6×</strong></td><td style="text-align:right;">0.92×</td></tr></tbody></table><p>PureFFT <code>:fast</code> is <strong>within ~1.2× of rustfft-AVX</strong> across all sizes and <strong>faster at n=65536</strong>. It is <strong>~2× faster than rustfft-scalar</strong> — the apples-to-apples comparison for the same algorithm.</p><h2 id="PureFFT-:fast-vs-FFTW-GFLOP/s,-earlier-measurements" tabindex="-1">PureFFT <code>:fast</code> vs FFTW (GFLOP/s, earlier measurements) <a class="header-anchor" href="#PureFFT-:fast-vs-FFTW-GFLOP/s,-earlier-measurements" aria-label="Permalink to &quot;PureFFT `:fast` vs FFTW (GFLOP/s, earlier measurements) {#PureFFT-:fast-vs-FFTW-GFLOP/s,-earlier-measurements}&quot;">​</a></h2><p>These measurements are from the <code>:fast</code> variant before the AVX Butterfly16/32 codelets were added (the radix-2 four-step path):</p><table tabindex="0"><thead><tr><th style="text-align:right;">n</th><th style="text-align:right;">FFTW-MEASURE</th><th style="text-align:right;">RustFFT</th><th style="text-align:right;">PureFFT <code>:fast</code></th><th style="text-align:right;">ratio</th></tr></thead><tbody><tr><td style="text-align:right;">1024</td><td style="text-align:right;">44</td><td style="text-align:right;">44</td><td style="text-align:right;">24</td><td style="text-align:right;">0.55×</td></tr><tr><td style="text-align:right;">4096</td><td style="text-align:right;">45</td><td style="text-align:right;">44</td><td style="text-align:right;">22</td><td style="text-align:right;">0.49×</td></tr><tr><td style="text-align:right;">16384</td><td style="text-align:right;">41</td><td style="text-align:right;">41</td><td style="text-align:right;">22</td><td style="text-align:right;">0.54×</td></tr><tr><td style="text-align:right;">65536</td><td style="text-align:right;">36</td><td style="text-align:right;">36</td><td style="text-align:right;">21</td><td style="text-align:right;">0.58×</td></tr><tr><td style="text-align:right;">262144</td><td style="text-align:right;">26</td><td style="text-align:right;">27</td><td style="text-align:right;">16</td><td style="text-align:right;">0.60×</td></tr></tbody></table><p>The current <code>:fast</code> (with AVX Butterfly codelets, table above) substantially improves these.</p><h2 id="All-variant-progression" tabindex="-1">All variant progression <a class="header-anchor" href="#All-variant-progression" aria-label="Permalink to &quot;All variant progression {#All-variant-progression}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Variant</th><th style="text-align:right;">GFLOP/s (F64)</th><th style="text-align:right;">Key technique</th></tr></thead><tbody><tr><td style="text-align:right;"><code>:scalar</code></td><td style="text-align:right;">7–9</td><td style="text-align:right;">Radix-2 baseline</td></tr><tr><td style="text-align:right;"><code>:base</code></td><td style="text-align:right;">11–17</td><td style="text-align:right;"><code>@simd ivdep</code> cross-pass</td></tr><tr><td style="text-align:right;"><code>:recursive</code></td><td style="text-align:right;">13–24</td><td style="text-align:right;"><code>@generated</code> codelets, cache-oblivious</td></tr><tr><td style="text-align:right;"><code>:soa</code></td><td style="text-align:right;">13–21</td><td style="text-align:right;">Split re/im (negative — split/merge overhead)</td></tr><tr><td style="text-align:right;"><code>:fourstep</code></td><td style="text-align:right;">16–22</td><td style="text-align:right;">Cache-blocked four-step</td></tr><tr><td style="text-align:right;"><code>:radix4</code></td><td style="text-align:right;">27–28</td><td style="text-align:right;">Port of rustfft Radix4 + cache-blocked transpose</td></tr><tr><td style="text-align:right;"><code>:radix4avx</code> / <code>:fast</code></td><td style="text-align:right;"><strong>35–40</strong></td><td style="text-align:right;">+ explicit SIMD.jl Butterfly16/32</td></tr><tr><td style="text-align:right;">FFTW-MEASURE</td><td style="text-align:right;">35–46</td><td style="text-align:right;">Reference</td></tr><tr><td style="text-align:right;">rustfft-AVX</td><td style="text-align:right;">35–51</td><td style="text-align:right;">Reference</td></tr></tbody></table><h2 id="Controlled-Julia-vs-Rust-same-algorithm" tabindex="-1">Controlled Julia vs Rust (same algorithm) <a class="header-anchor" href="#Controlled-Julia-vs-Rust-same-algorithm" aria-label="Permalink to &quot;Controlled Julia vs Rust (same algorithm) {#Controlled-Julia-vs-Rust-same-algorithm}&quot;">​</a></h2><p>To separate <strong>language</strong> from <strong>algorithm</strong>, we ran the identical radix-2 DIT kernel in both Julia and Rust (same layout, same twiddle indexing, same <code>muladd</code>/<code>mul_add</code> FMA, same <code>@inbounds</code> / <code>get_unchecked</code>). Checksums match bit-for-bit.</p><table tabindex="0"><thead><tr><th style="text-align:right;">n</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Rust</th><th style="text-align:right;">winner</th></tr></thead><tbody><tr><td style="text-align:right;">64</td><td style="text-align:right;">267 ns</td><td style="text-align:right;">240 ns</td><td style="text-align:right;">Rust +11%</td></tr><tr><td style="text-align:right;">256</td><td style="text-align:right;">1211 ns</td><td style="text-align:right;">1111 ns</td><td style="text-align:right;">Rust +9%</td></tr><tr><td style="text-align:right;">1024</td><td style="text-align:right;">5266 ns</td><td style="text-align:right;">5346 ns</td><td style="text-align:right;">tie</td></tr><tr><td style="text-align:right;">4096</td><td style="text-align:right;">24309 ns</td><td style="text-align:right;">26598 ns</td><td style="text-align:right;">Julia +9%</td></tr><tr><td style="text-align:right;">16384</td><td style="text-align:right;">143956 ns</td><td style="text-align:right;">237816 ns</td><td style="text-align:right;">Julia +65%</td></tr><tr><td style="text-align:right;">65536</td><td style="text-align:right;">1.10 ms</td><td style="text-align:right;">1.32 ms</td><td style="text-align:right;">Julia +20%</td></tr><tr><td style="text-align:right;">262144</td><td style="text-align:right;">6.83 ms</td><td style="text-align:right;">7.39 ms</td><td style="text-align:right;">Julia +8%</td></tr></tbody></table><p><strong>Conclusion: same algorithm ⇒ same speed. The language is not the lever.</strong></p><p>The earlier &quot;PureFFT is 2× slower than rustfft&quot; result was about algorithm choice, not language. Once we ported the same algorithm (rustfft&#39;s <code>Radix4</code>) to Julia and added AVX codelets, the gap vanished.</p><h2 id="Methodology" tabindex="-1">Methodology <a class="header-anchor" href="#Methodology" aria-label="Permalink to &quot;Methodology {#Methodology}&quot;">​</a></h2><ul><li><p><strong>Timing</strong>: BenchmarkTools <code>@belapsed</code> with <code>setup=(y=copy(x)) evals=1</code>, min over ≥400 samples.</p></li><li><p><strong>In-place</strong>: all transforms applied in-place on a fresh copy per sample.</p></li><li><p><strong>Planning excluded</strong>: plans built once outside the timing loop.</p></li><li><p><strong>Single-threaded</strong>: <code>FFTW.set_num_threads(1)</code>; RustFFT and PureFFT are single-thread by design.</p></li><li><p><strong>Correctness</strong>: all variants validated against FFTW, relative error ≤ 5e-16.</p></li></ul>',21)])])}const u=e(s,[["render",d]]);export{y as __pageData,u as default};
